#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1<<22|15;int head[N],des[N],nxt[N],cgt,n,m,a[N];bool vis[N];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
inline void dfs(int u)
{
	vis[u]=true;for(int i=head[u];i;i=nxt[i]){int v=des[i];if(!vis[v])dfs(v);}
	for(int i=0;i<n;++i)if((u>>i&1)&&!vis[u^(1<<i)])dfs(u^(1<<i));
}
int main()
{
	n=read();m=read();rep(1,m,i)a[i]=read(),ins(a[i],a[i]^((1<<n)-1));
	int ans=0;rep(1,m,i)if(!vis[a[i]])dfs(a[i]),++ans;printf("%d\n",ans);return 0;
}
